#include <stdio.h>
#include <pthread.h>
#include <semaphore.h>

sem_t mutex;
int counter = 0;

void* increment(void* arg) {
 for (int i = 0; i < 100000; i++) {
 sem_wait(&mutex); // P operation
 counter++; // Critical section
 sem_post(&mutex); // V operation
 }
 return NULL;
}

int main() {
 pthread_t t1, t2;

 sem_init(&mutex, 0, 1); // Binary semaphore

 pthread_create(&t1, NULL, increment, NULL);
 pthread_create(&t2, NULL, increment, NULL);

 pthread_join(t1, NULL);
 pthread_join(t2, NULL);

 sem_destroy(&mutex);

 printf("Counter: %d (expected: 200000)\n", counter);
 return 0;
}

import java.util.concurrent.Semaphore;

public class SemaphoreExample {
 static Semaphore mutex = new Semaphore(1);
 static int counter = 0;

 public static void main(String[] args) throws Exception {
 Runnable task = () -> {
 for (int i = 0; i < 100000; i++) {
 try {
 mutex.acquire(); // wait
 counter++; // Critical section
 mutex.release(); // signal
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 }
 };

 Thread t1 = new Thread(task);
 Thread t2 = new Thread(task);

 t1.start(); t2.start();
 t1.join(); t2.join();

 System.out.println("Counter: " + counter);
 }
}

#include <stdio.h>
#include <pthread.h>
#include <semaphore.h>
#include <unistd.h>

#define NUM_RESOURCES 3
#define NUM_THREADS 5

sem_t resources;

void* use_resource(void* arg) {
 int id = *(int*)arg;

 printf("Thread %d: Waiting for resource\n", id);
 sem_wait(&resources); // Acquire resource

 printf("Thread %d: Using resource\n", id);
 sleep(1); // Simulate resource usage

 printf("Thread %d: Releasing resource\n", id);
 sem_post(&resources); // Release resource

 return NULL;
}

int main() {
 pthread_t threads[NUM_THREADS];
 int ids[NUM_THREADS];

 sem_init(&resources, 0, NUM_RESOURCES);

 for (int i = 0; i < NUM_THREADS; i++) {
 ids[i] = i;
 pthread_create(&threads[i], NULL, use_resource, &ids[i]);
 }

 for (int i = 0; i < NUM_THREADS; i++) {
 pthread_join(threads[i], NULL);
 }

 sem_destroy(&resources);
 return 0;
}

import java.util.concurrent.Semaphore;

public class CountingSemaphore {
 static final int NUM_RESOURCES = 3;
 static final int NUM_THREADS = 5;
 static Semaphore resources = new Semaphore(NUM_RESOURCES);

 public static void main(String[] args) {
 for (int i = 0; i < NUM_THREADS; i++) {
 final int id = i;
 new Thread(() -> {
 try {
 System.out.println("Thread " + id + ": Waiting");
 resources.acquire();

 System.out.println("Thread " + id + ": Using resource");
 Thread.sleep(1000);

 System.out.println("Thread " + id + ": Releasing");
 resources.release();
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 }).start();
 }
 }
}

#include <stdio.h>
#include <pthread.h>
#include <semaphore.h>

sem_t sync_sem;

void* task_A(void* arg) {
 printf("A: Doing work before signal\n");
 // S1 must happen before S2
 printf("A: Signal sent\n");
 sem_post(&sync_sem); // Signal B to continue
 return NULL;
}

void* task_B(void* arg) {
 printf("B: Waiting for signal\n");
 sem_wait(&sync_sem); // Wait for A's signal
 printf("B: Received signal, continuing\n");
 // S2 happens after S1
 return NULL;
}

int main() {
 pthread_t tA, tB;

 sem_init(&sync_sem, 0, 0); // Start at 0

 // Start B first, but it will wait for A
 pthread_create(&tB, NULL, task_B, NULL);
 pthread_create(&tA, NULL, task_A, NULL);

 pthread_join(tA, NULL);
 pthread_join(tB, NULL);

 sem_destroy(&sync_sem);
 return 0;
}

import java.util.concurrent.Semaphore;

public class SemaphoreOrdering {
 static Semaphore sync = new Semaphore(0);

 public static void main(String[] args) throws Exception {
 Thread taskB = new Thread(() -> {
 try {
 System.out.println("B: Waiting for signal");
 sync.acquire(); // Wait
 System.out.println("B: Continuing (S2)");
 } catch (InterruptedException e) {
 Thread.currentThread().interrupt();
 }
 });

 Thread taskA = new Thread(() -> {
 System.out.println("A: Doing work (S1)");
 try { Thread.sleep(500); } catch (Exception e) {}
 System.out.println("A: Signaling B");
 sync.release(); // Signal
 });

 taskB.start();
 taskA.start();

 taskA.join();
 taskB.join();
 }
}
